head.script:
scwin.trvMenu_onclick = function(value, nodeElement, index) {
	var tmpRs = trvMenu.getSelectedNode();
	if (!tmpRs) {
		return;
	}
	var childNode = tmpRs.childNodes;

	for (var i = 0; i < childNode.length; i++) {
		if (childNode[i].isLeaf()) {
			// console.log(eval("trvMenu_label_" + childNode[i].index).classList);
			eval(comLib.getFrameId($p) + "trvMenu_label_" + childNode[i].index).classList.add("none-childlo");
		}
		// if(tmpRs[i].index != tmpRs.index){
			// trvMenu.spanNode(depth1[i].index, false , true);
		// }
		// eval("trvMenu_label_" + childNode[i].index).classList.removeClass("w2treeview_label");
	}

	$p.$(".w2treeview_label").removeClass("w2treeview_select_node");

	if (tmpRs.depth == 1) {
		var depth1 = tmpRs.parentNode.childNodes;
		for (var i = 0; i < depth1.length; i++) {
			if (depth1[i].index != tmpRs.index) {
				trvMenu.spanNode(depth1[i].index, false , true);
			}
		}
	}

	if (tmpRs.depth == 2) {
		var depth2 = tmpRs.parentNode.childNodes;
		for (var i = 0; i < depth2.length; i++) {
			if (depth2[i].index != tmpRs.index) {
				trvMenu.spanNode(depth2[i].index, false, true);
			}
		}
	}

	if (tmpRs.depth == 3) {
		var depth3 = tmpRs.parentNode.childNodes;
		for (var i = 0; i < depth3.length; i++) {
			if (depth3[i].index != tmpRs.index) {
				trvMenu.spanNode(depth3[i].index, false, true);
			}
		}
	}

	if (tmpRs.depth == 4) {
		var depth4 = tmpRs.parentNode.childNodes;
		for (var i = 0; i < depth4.length; i++) {
			if (depth4[i].index != tmpRs.index) {
				trvMenu.spanNode(depth4[i].index, false, true);
			}
		}
	}

	if (tmpRs.parentNode.index != 0) {
		if (tmpRs.parentNode.parentNode.parentNode != null && tmpRs.parentNode.parentNode.parentNode.depth != 0) {
			eval(comLib.getFrameId($p) + "trvMenu_label_" + tmpRs.parentNode.parentNode.parentNode.index).classList.add("w2treeview_select_node");
		}

		if (tmpRs.parentNode.parentNode != null && tmpRs.parentNode.parentNode.depth != 0) {
			eval(comLib.getFrameId($p) + "trvMenu_label_" + tmpRs.parentNode.parentNode.index).classList.add("w2treeview_select_node");
		}

		if (tmpRs.parentNode != null && tmpRs.parentNode.depth != 0) {
			eval(comLib.getFrameId($p) + "trvMenu_label_" + tmpRs.parentNode.index).classList.add("w2treeview_select_node");
		}
	}

	if (trvMenu.isLeaf() == true) {
		// 메뉴 JSON 객체
		var jsonObj = dltLeftMenuList.getMatchedJSON("menuId", value, true)[0];

		if (jsonObj != undefined && jsonObj != null) {
			if (value == "ECSWD160000") { // 주요정보
				// comLib.initBoard($p, "02");
				$(".btn_m_icon2").trigger("click");
			} else if (jsonObj.callParm.indexOf("ntt") == 0) {
				comLib.initBoard($p, jsonObj.callParm);
			} else {
				// 윈도우 컨테이너 Maxnum 체크
				if ($p.top().wdcMain.currentWindowNum == $p.top().wdcMain.options.windowMaxNum - 1) {
					// 화면은 총 {0}개까지만 허용됩니다.
					// alert(utilLib.getMessage("ECS.INFO.00010", "10")[0]);
					$p.top().wdcMain.windows[1].window.close();
				}

				var existWindow = false;
				for (var i = 0; i < $p.top().wdcMain.currentWindowNum; i++) {
					if ($p.top().wdcMain.getWindowByWindowId(jsonObj.scrinId) != null) {
						existWindow = true;
						$p.top().wdcMain.getWindowByWindowId(jsonObj.scrinId, true);
						break;
					}
				}

				// 하위메뉴가 없고 scrinUrl 있는 경우 화면 오픈
				if (existWindow == false) {
					var menuInfo = {
						"menuId" : jsonObj.menuId,
						"menuNm" : jsonObj.menuNm,
						"scrinId" : jsonObj.scrinId,
						"conectParamCtnt" : jsonObj.callParm
					};
					var param = jsonObj.callParm;

					if (param == null || param == "") {
						param = "";
					} else {
						param = "?" + param;
					}

					if (value == "ECSZZ510000" || value == "ECSZZ520000" || value == "ECSZZ530000" || value == "ECSZZ540000" || value == "ECSZZ550000") {
						scwin.oldSysCall(value);
						return;
					} else if (value == "ECSEC510000" || value == "ECSEC520000" || value == "ECSEC530000" || value == "ECSEC540000" ) {
						if (jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
							var dataObj = {
								"type" : "json",
								"name" : "param",
								"data" : {
									"basin" : jsonObj.callParm
								}
							};
							scwin.createWindow(jsonObj.menuDc, null, jsonObj.scrinUrl, jsonObj.menuDc, "main_ecs_detail", "existWindow", null, null, null, null, "wframe", dataObj);
							return;
						}
					}
					/*
					else if(value == "ECSEG321000") { //전력입찰수행 크롬->익스로 오픈
						if (navigator.userAgent.indexOf("Chrome") != -1) { // 크롬이면
							scwin.ieSysCall(value);
							return;
						}
					} else if (value == "ECSPG990000") {
					}
					*/

					if (jsonObj.popupYn == null || jsonObj.popupYn != "Y") {
						// 화면 오픈
						// setTimeout(function() {
							// createWindow(title, iconUrl, src, windowTitle, windowId, openAction, closeAction, windowTooltip)
							if (jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
								scwin.createWindow(jsonObj.menuNm, null, jsonObj.scrinUrl + param, jsonObj.menuNm, jsonObj.scrinId, null, null, null, null, null, null, null);
							}
						// }, 200);
					} else {
						// 팝업창
						var option = scwin.makePopupOption(jsonObj); // {popupID : jsonObj.scrinId, width : 1300, height : 830, title : jsonObj.menuNm};
						var usrInfo = comLib.getUserInfo4Param(comLib.dataDecEnc(utilLib.getDate(), "E"), encodeURI(option.title));
						var jsonPopupObj = {
							"userInfo" : usrInfo,
							"closeCallbackFncName" : "",
							"popupId" : option.popupID
						};
						if (jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
							if (jsonObj.scrinUrl.indexOf("http") == 0) {
								comLib.openGetWinPopup($p, jsonObj.scrinUrl + param, option, jsonPopupObj);
							} else {
								if (jsonObj.scrinUrl.endsWith("guide.xml")) {
									var jsonPopupParam = ecsLib.queryStringToJSON(param);

									var options = {
										type : "window", // window, wframePopup
										title : "온라인 도움말",
										width : 1500,
										height : 900,
										modal : false,
										popupParam : {
											data : jsonPopupParam
										}
									};
									comLib.openPopup($p, option.popupID, jsonObj.scrinUrl + param, options);
								} else {
									comLib.openGetWinPopup($p, comLib.ECS_POP_URL + jsonObj.scrinUrl + param, option, jsonPopupObj);
								}
							}
						}
					}
					// 메뉴 로그
					comLib.insertMenuLog($p, menuInfo);
				}
			}
		}
	} else {
		// 하위 메뉴가있고 jsonObj.scrinUrl 있는경우 화면 오픈
		var jsonObj = dltLeftMenuList.getMatchedJSON("menuId", value, true)[0];

		if (jsonObj != undefined && jsonObj != null) {
			if(jsonObj.scrinUrl != undefined && jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
				if ($p.top().wdcMain.currentWindowNum == $p.top().wdcMain.options.windowMaxNum - 1) {
					$p.top().wdcMain.windows[1].window.close();
				}
				var existWindow = false;
				for (var i = 0; i < $p.top().wdcMain.currentWindowNum; i++) {
					if ($p.top().wdcMain.getWindowByWindowId(jsonObj.scrinId) != null) {
						existWindow = true;
						$p.top().wdcMain.getWindowByWindowId(jsonObj.scrinId, true);
						break;
					}
				}

				if (existWindow == false) {
					var menuInfo = {
						"menuId" : jsonObj.menuId,
						"menuNm" : jsonObj.menuNm,
						"scrinId" : jsonObj.scrinId,
						"conectParamCtnt" : jsonObj.callParm
					};
					var param = jsonObj.callParm;

					if (param == null || param == "") {
						param = "";
					} else {
						param = "?" + param;
					}

					if (jsonObj.popupYn == null || jsonObj.popupYn != "Y") {
						// 화면 오픈
						// setTimeout(function() {
							// createWindow(title, iconUrl, src, windowTitle, windowId, openAction, closeAction, windowTooltip)
							if (jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
								scwin.createWindow(jsonObj.menuNm, null, jsonObj.scrinUrl + param, jsonObj.menuNm, jsonObj.scrinId, null, null, null, null, null, null, null);
							}
						// }, 200);
					} else {
						// 팝업창
						var option = scwin.makePopupOption(jsonObj); // { popupID : jsonObj.scrinId, width : 1300, height : 830, title : jsonObj.menuNm};
						var usrInfo = comLib.getUserInfo4Param(comLib.dataDecEnc(utilLib.getDate(), "E"), encodeURI(option.title));
						var jsonPopupObj = {
							"userInfo" : usrInfo,
							"closeCallbackFncName" : "",
							"popupId" : option.popupID
						};

						if (jsonObj.scrinUrl != null && jsonObj.scrinUrl != "") {
							if (jsonObj.scrinUrl.indexOf("http") == 0) {
								comLib.openGetWinPopup($p, jsonObj.scrinUrl + param, option, jsonPopupObj);
							} else {
								comLib.openGetWinPopup($p, comLib.SCM_POP_URL + jsonObj.scrinUrl + param, option, jsonPopupObj);
							}
						}
					}

					// 메뉴 로그
					comLib.insertMenuLog($p, menuInfo);
				}
			}
		}
	}
};

// 윈도우 컨테이너 생성
scwin.createWindow = function(title, iconUrl, src, windowTitle, windowId, openAction, closeAction, windowTooltip, windowHeaderHTML, options, m_frameMode, dataObj) {
	// 윈도우 컨테이너 Maxnum 체크
	if ($p.top().wdcMain.currentWindowNum == $p.top().wdcMain.options.windowMaxNum - 1) {
		// 화면은 총 {0}개까지만 허용됩니다.
		// alert(utilLib.getMessage("ECS.INFO.00010", "10")[0]);
		$p.top().wdcMain.windows[1].window.close();
	}
	if (src.indexOf("/openOthrSysScrn.do") === 0) {
		$p.top().wdcMain.createWindow(title , iconUrl , comLib.getContextPath() + src, windowTitle, windowId,
			openAction, closeAction, windowTooltip, windowHeaderHTML, options, m_frameMode || "iframe", dataObj);
	} else {
		setTimeout(function() { 
			$p.top().wdcMain.createWindow(title , iconUrl , comLib.getContextPath() + src, windowTitle, windowId,
				openAction, closeAction, windowTooltip, windowHeaderHTML, options, m_frameMode || "wframe", dataObj);
		}, 200);
	}
};

// 팝업창 사이즈 및 타이틀 설정
scwin.makePopupOption = function(menu) {
	var title = menu.menuNm;
	var width = 1300; // 일반창의 기본 width (협의 후 알맞게 수정해 주세요.)
	var height = 770; // 일반창의 기본 height (협의 후 알맞게 수정해 주세요.)

	var param = menu.callParm;

	if (param != null && param != "") {
		var params = param.split("&");

		for (var i = 0; i < params.length; i++) {
			var obj = params[i].split("="); // key, value 로 분리
			var value = obj[1];

			switch (obj[0]) {
				case "width":
					if (!isNaN(value)) {
						width = parseInt(value);
					}
					break;

				case "height":
					if (!isNaN(value)) {
						height = parseInt(value);
					}
					break;

				case "title":
					title = value;
			}
		}
	}

	var option = {
		popupID : menu.scrinId,
		width : width,
		height : height,
		title : title
	};

	return option;
};

scwin.navHeight = function() {
	var wheight= $(window).height() - 112;
	$p.$("#navi").css({"height": wheight + "px"});
};

scwin.usermenu = function() {
	$p.$(".usermenu ul li a").click(function () {
		$p.$(".usermenu ul li").removeClass("m-on");
		$(this).parent().addClass("m-on");
	});
	$p.$(".btn_m_star").click(function () { 
		$p.$(".navi-tree").css("display","none");
		$p.$(".favorate").css("display","block");
		scwin.selectUsrBkMk();
	});
	$p.$(".btn_m_menu").click(function () {
		$p.$(".navi-tree").css("display","block");
		$p.$(".mCSB_container").css("width","240px");
		$p.$(".favorate").css("display","none");
	});
	/**
	 * 사이트맵 20181116
	 */
	$(".btn_m_grid").click(function() {
		if ($p.top().wdcMain.getWindowByWindowId("사이트맵") != null) {
			$p.top().wdcMain.getWindowByWindowId("사이트맵", true);
		} else {
			scwin.createWindow("사이트맵", null, "/ui/common/sitemap.xml", "사이트맵", "site_map", null, null, null, null, null, "wframe", null);
		}
	});
	/*
	$(".btn_m_grid").click(function () {
		scwin.createWindow("사이트맵", null, "/ui/common/sitemap.xml", "사이트맵", "site_map");
	});
	*/
};

// 윈도우 리사이즈
window.onresize = function() {
	scwin.navHeight();

	$p.$("#grpFav").mCustomScrollbar({
		axis : "yx",
		theme : "minimal",
		setHeight : parseInt($p.$(".usermenu").css("height").replace("px", "")) - 112,
		setWidth : "240px"
	});

	$p.$("#grpFav").mCustomScrollbar().css("height", parseInt($p.$(".usermenu").css("height").replace("px", "")) - 112);
	$p.$("#grpFav").mCustomScrollbar().css("width", "240px");
};

