 /**
 * 시스템명 클릭
 */
scwin.grpMain_onclick = function(e) {
	var mainId = "main_ecs";
	if($p.top().wdcMain.getWindowByWindowId(mainId) != null) {
		$p.top().wdcMain.getWindowByWindowId(mainId, true);
		// 메인화면 재조회
		$p.top().wdcMain.getWindow(mainId).scwin.searchDatas();
	} else {
		scwin.createWindow("에너지전주기", null, "/ui/main/main_ecs.xml", "에너지전주기", mainId, null, null, null, null, null, "wframe", null);
		// wdcMain.createWindow("에너지전주기", null, "/ui/main/main_ecs.xml", "에너지전주기", mainId, null, "scwin.mainEcsClose", null, null, null, "wframe", null);
	}
};

/**
 * 구시스템 호출하기
 */
scwin.oldSysCall = function(value){
	var requestData = {
		"dmaInqireParam" : {
			"intnSysDivCd" : comLib.getSysDivCd(),
			"useYn" : "Y",
			"scrinId" : value
		}
	};
	var option = {
		action : "zz/authmng/selectLnkSys.do",
		reqData : requestData,
		success : function(res) {
			var url = "";
			if (res.data.menuId == "ECSZZ510000" || res.data.menuId == "ECSZZ520000") {
				url = res.data.scrinUrl + "?empno=" + res.data.usrId;
			} else {
				url = res.data.scrinUrl;
			}
			if (res.data.popupYn == "Y") {
				var callParm = (dltLeftMenuList.getAllJSON().find(obj => obj.scrinId == res.data.scrinId) || 0).callParm
					|| "toolbar=no,menubar=yes,location=no,directories=yes,status=yes,scrollbars=yes,resizable=yes,width=1300,height=830,fullscreen=yes";
				window.open(url, "ecslink", callParm);
			}
		},
		isselectAsisCmsPageLinkShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 크롬IE호출(기상) 
 */
scwin.ieSysWiCall = function(value){
	var jsonObj = dltLeftMenuList.getMatchedJSON("menuId", value, true)[0];

	// var  lnkUrl = "https://ecs.[BASE_DOMAIN]/openOthrSysScrn.do?screenId="+jsonObj.scrinUrl.replace("/ui","")+"&targetSystem=ECS&menuId="+value;
	var lnkUrl = "https://ecs.[BASE_DOMAIN]/openOthrSysMnu.do?screenId="+jsonObj.scrinUrl.replace("/ui","")+"&targetSystem=ECS&menuId="+value;

	lnkUrl += "&usrId=" + comLib.getUsrId();
	lnkUrl += "&docNo=";

	// IE_OPEN.setSrc("ieecshttp:// + " + lnkUrl);
	IE_OPEN.setSrc("ieoasisportalhttp:// + " + lnkUrl);
};

/**
 * 크롬IE호출
 */
scwin.ieSysCall = function(value) {
	var jsonObj = dltLeftMenuList.getMatchedJSON("menuId", value, true)[0];
	// var lnkUrl  =location.origin + "/openOthrSysScrn.do?screenId=" + jsonObj.scrinUrl.replace("/ui","") + "&targetSystem=ECS&menuId=" + value;
	// var lnkUrl  =comLib.ECS_POP_URL.replace("/wq/winPopup.jsp?w2xPath=","") + "/openOthrSysScrn.do?screenId=" + jsonObj.scrinUrl.replace("/ui", "") + "&targetSystem=ECS&menuId=" + value;

	var lnkUrl = "https://ecs.[BASE_DOMAIN]/openOthrSysScrn.do?screenId=" + jsonObj.scrinUrl.replace("/ui", "") + "&targetSystem=ECS&menuId=" + value;
	// var lnkUrl = "https://ecs.[BASE_DOMAIN]/openOthrSysMnu.do?screenId=" + jsonObj.scrinUrl.replace("/ui", "") + "&targetSystem=ECS&menuId=" + value;

	lnkUrl += "&usrId=" + comLib.getUsrId();
	lnkUrl += "&docNo=";

	// IE_OPEN.setSrc("ieecshttp:// + " + lnkUrl);
	IE_OPEN.setSrc("ieoasisportalhttp:// + " + lnkUrl);
};
